class Solution:
    def maxTaskAssign(self, tasks: List[int], workers: List[int], pills: int, strength: int) -> int:
        tasks.sort()
        workers.sort(reverse=True)
        def possible(amt):
            need_pill = 0
            for i in range(amt):
                if workers[i] < tasks[-i-1]:
                    need_pill += 1
                    if need_pill > pills or workers[i] + strength < tasks[-i-1]:
                        return False
            return True
        lo, hi = 0, min(len(tasks), len(workers))
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if possible(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo
